function LWonderManager:InitCtrl(map)

    self._seqCom = SequenceCom:New()
    self._dynamicObjList = {}

    self._monsterTagPath = {
        [0] = "wonderland_txt_4",
        [1] = "wonderland_txt_2",
        [2] = "wonderland_txt_3",

    }

    self._map = map

    local mapTran = self._map:GetMapTrans()

    local layerRoot = CS.FindTrans(mapTran,"LayerRoot")
    local effRoot= CS.FindTrans(layerRoot,"LayerEffect")
    local objRoot= CS.FindTrans(layerRoot,"LayerObject")
    local iconRoot = CS.FindTrans(layerRoot,"LayerIcon")
    local iconTemplate = CS.FindTrans(layerRoot,"TemplateRoot/EventTemplate")

    self._iconCtrl = LWonderIconCtrl:New()
    self._iconCtrl:InitCtrl(iconRoot,iconTemplate)

    self._effCtrl = LWonderEffectCtrl:New()
    self._effCtrl:InitCtrl(effRoot)

    self._objCtrl = LWonderObjectCtrl:New()
    self._objCtrl:InitCtrl(objRoot)

    self._wonderGridList = {}
end

function LWonderManager:GetMapName()
    if self._map then
        return self._map:GetMapName()
    end
end

function LWonderManager:RefreshGrid(isFirst)
    if self._waitMoveTag then
        return
    end

    local gridList = self._map:GetGridList()
    local uiItemList = {}
    for k,v in pairs(gridList) do
        table.insert(uiItemList,v)
    end

    table.sort(uiItemList,function (a,b)
        return a.gridKey<b.gridKey
    end)

    local index = 0
    local delay = 0.05
    local solidDelay = 1.8

    for k,v in ipairs(uiItemList) do
        local item = v.item
        local itemdata = v.itemdata

        local totalDelay = 0
        if isFirst then
            index = index+ 1
            totalDelay = delay*index + solidDelay
        end


        self:OnShowGrid(item,itemdata,totalDelay)
    end

    self:RefreshAllowArrow()

    if isFirst then
        self._map:SendGuideReady()
    end

end

function LWonderManager:RefreshGridEvent()
    if LOG_INFO_ENABLED then
        print("LWonderManager:RefreshGridEvent()")
    end
    local gridList = self._map:GetGridList()
    local uiItemList = {}
    for k,v in pairs(gridList) do
        table.insert(uiItemList,v)
    end

    table.sort(uiItemList,function (a,b)
        return a.gridKey<b.gridKey
    end)

    for k,v in ipairs(uiItemList) do
        local item = v.item
        local itemdata = v.itemdata
        local gridKey = v.gridKey
        local grid = self._wonderGridList[gridKey]
        if grid then
           grid:ShowGridEvent(item,itemdata)
        end
    end

    self:RefreshAllowArrow()
end

function LWonderManager:FormatGridTween(item)
    item.transform.localScale = Vector3.New(0,0,0)
    local tweener = item.transform:DOScale(Vector3.New(1,1,1),0.2)
    return tweener
end

function LWonderManager:OnGridTweenEnd()

end

function LWonderManager:Clear()

    if self._wonderGridList then
        for k,v in pairs(self._wonderGridList) do
            v:Destroy()
        end
        self._wonderGridList = nil
    end

    if self._iconCtrl then
        self._iconCtrl:Clear()
    end
    if self._effCtrl then
        self._effCtrl:Clear()

    end
    if self._objCtrl then
        self._objCtrl:Clear()
    end

    table.removeall(self)
end

function LWonderManager:OnShowGrid(item,itemdata,interval)
    local layerIndex = itemdata:GetLayerIndex()
    local gridIndex= itemdata:GetGridIndex()
    local gridKey = gModelWonderland:FormatGridKey(layerIndex,gridIndex)
    local grid = self._wonderGridList[gridKey]
    if not grid then
        grid = LWonderGrid:New(self)
        grid:Create(item,itemdata,interval)
        self._wonderGridList[gridKey] = grid
        return
    end
    grid:RefreshGrid(item,itemdata)

end

function LWonderManager:GetIconCtrl()
    return self._iconCtrl
end

function LWonderManager:GetEffCtrl()
    return self._effCtrl
end

function LWonderManager:GetObjCtrl()
    return self._objCtrl
end

function LWonderManager:CreateMainRole()
    local themeId = gModelWonderland:GetThemeId()
    local spineName = gModelWonderland:GetRoleRes(themeId)
    local curLayer = gModelWonderland:GetCurLayer()
    local curGrid = gModelWonderland:GetCurGrid()
    local gridKey = gModelWonderland:FormatGridKey(curLayer,curGrid)
    self._gridKey = gridKey
    local gridList = self._map:GetGridList()
    local item = gridList[gridKey].item
    local pos = item.position + Vector3.New(0,0,0)

    local roleObj = self._roleObj
    if not roleObj then
        --CS.ShowObject(self.mSpineRoot,false)

        local objData =
        {
            key = "mainRole",
            pos = pos,
            spineName = spineName,
            scale = 0.7,
            func = function (spine)
                spine:PlayAnimation(0,"idle",true)
                self:RefreshRoleBuffShow()
                self:RefreshSpecialEvent()

                self:RefreshRolePos()
            end
        }
        roleObj = LWonderRoleObject:New(self)
        self._roleObj = roleObj
        roleObj:Create(objData)
        roleObj:StartLoad()
    end
end

