function LWonderManager:RefreshRolePos()

    if gLGameUI:IsExistOneWnd(waitWndList) then
        printInfoN("gLGameUI:IsExistOneWnd(waitWndList)")
        return
    end


    if self._waitEvent then
        printInfoN("self._waitEvent "..self._waitEvent)
        self:ShowWaitEffect()
        return
    end

    local curLayer = gModelWonderland:GetCurLayer()
    local curGrid = gModelWonderland:GetCurGrid()
    local gridKey = gModelWonderland:FormatGridKey(curLayer,curGrid)

    local oldGridKey = self._gridKey

    if oldGridKey and oldGridKey ~= gridKey then

        local endCall = function()
            self._gridKey = gridKey

            printInfoN("jump end")
            self:RefreshGridState()
            self:RefreshGridEvent()

            gModelWonderland:CheckShowHud(ModelWonderland.EVENT_SNOW)

            self:RefreshRoleBuffShow()

            local grid = self._wonderGridList[gridKey]
            if grid then
                grid:OnReach()
            end

            if oldGridKey then
                local startGrid = self._wonderGridList[oldGridKey]
                if startGrid then
                    startGrid:RefreshBeanVine()
                end
            end

            self._roleObj:DeleteEffect("ui_fx_tubiaotuowei01")
            self._roleObj:DeleteEffect("qjtx_icon_16")

            self:RefreshSpecialEvent()

            FireEvent(EventNames.ON_WONDER_ROLE_MOVE_FINISH)
        end
        local gridList = self._map:GetGridList()
        local item = gridList[gridKey].item
        if not CS.IsValidObject(item)  then
            return
        end
        local targetPos = item.transform.position

        local obj = self._roleObj
        if obj and self._roleObj:IsReady()  then
            local wondergrid = self._wonderGridList[oldGridKey]
            if wondergrid then
                wondergrid:OnToOther(function (addEvent)
                    local jumpData =
                    {
                        targetPos = targetPos,
                        endCall = endCall,
                    }
                    obj:JumpTo(jumpData)

                    if addEvent then
                        local effData =
                        {
                            type = 1,
                            effName = "ui_fx_tubiaotuowei01",
                            scale = 1,
                            offset = Vector3.zero

                        }
                        obj:AddEffect(effData)

                        if addEvent == ModelWonderland.EVENT_POD then
                            effData =
                            {
                                type = 2,
                                effName = "qjtx_icon_16",
                                scale = 1,
                                offset = Vector3.zero
                            }
                            obj:AddEffect(effData)
                        end
                    end


                    --todo startFollow
                    local trans = self._roleObj:GetDisplayTrans()
                    if CS.IsValidObject(trans) then
                        self._map:FollowRole(trans,Vector3.New(0,0.5,0),0.1)
                    end
                end)
            end
        end
    else
        self:RefreshGridState()
        self:RefreshGridEvent()
        self:RefreshSpecialEvent()
    end
end

function LWonderManager:RefreshGridState()
    local oldStateRecord = gModelWonderland:GetGridOldState()
    local newStateRecord = gModelWonderland:CreateStateRecord()
    gModelWonderland:ClearOldRecord()
    gModelWonderland:GetGridOldState() --重新记录一份
    for k,v in pairs(self._wonderGridList) do
        local oldState = oldStateRecord[k]
        local newState = newStateRecord[k]
        if oldState ~= newState then
            v:ChangeState(oldState,newState)
        end
    end
end

function LWonderManager:GetGridByKey(gridKey)
    local grid = self._wonderGridList[gridKey]
    return grid
end

function LWonderManager:PlayBehit(eventId)

    local eventCfg = gModelWonderland:GetEventConfig(eventId)
    local eventType = eventCfg.type
    local effName,type
    if eventType == ModelWonderland.EVENT_ARROW_TOWER or eventType == ModelWonderland.EVENT_POISON then
        local para  =eventCfg.parameter
        local strs = string.split(para,"=")
        effName = strs[#strs]
        type = 1

        gModelWonderland:CheckShowHud(eventType)
    end

    if self._roleObj then
        self._roleObj:PlayBeHit(0.33)

    end

    local effData = nil

    if type == 1 then

        effData =
        {
            type = 1,
            effName = effName,
            scale = 0.7,
            offset = Vector3.New(-0.4,-0.05,0)
        }
        self._roleObj:AddEffect(effData)
    end


    if eventType == ModelWonderland.EVENT_CLIP then
        local delay = 1
        local seq = self._seqCom:CreateSeq("delayFreeze")
        seq:AppendInterval(delay)
        seq:OnComplete(function ()
            self._seqCom:DeleteSeq("delayFreeze")
            local buff =
            {
                type = 1,
                effName = "fx_buff_xuanyun",
                scale = 0.5,
                offset = Vector3.New(0,1,0),
                duration = 5,
            }
            self._roleObj:AddEffect(buff)
            self._roleObj:ShowFreeze(5)
        end)

        seq:PlayForward()

        gModelWonderland:CheckShowHud(eventType)
    end


end

function LWonderManager:RefreshAllowArrow()
    local layerDatas = gModelWonderland:GetLayerInfo()

    local list ={}
    for k,v in pairs(layerDatas) do
        local grids = v.grids
        for k1,v1 in pairs(grids) do
            local state = v1:GetStatus()
            if state == StructWonderlandGrid.ALLOW or state == StructWonderlandGrid.SELECTED then
                local gridKey = v1:GetGridKey()

                table.insert(list,gridKey)
            end
        end
    end
    if self._arrowList then
        for k,v in ipairs(self._arrowList) do
            self._seqCom:DeleteSeq(v)
            self._iconCtrl:DestroyByKey(v)
        end
    end

    self._arrowList = {}

    for k,v in ipairs(list) do
        local item = self:GetMapItem(v)
        if item then
            local pos = item.item.position
            local key = "arrow_"..v
            local data =
            {
                key = key,
                resName = "wonderland_ui_arrow_1",
                scale = 1,
                pos = pos + Vector3.New(0,1.4,0),
                sorting = LGamePlayType.WONDER_SORTING_ARROW,
                endFunc = function(go)
                    local tran = go.transform
                    local seq =self._seqCom:CreateSeq(key)
                    local tweener
                    local pos = tran.localPosition
                    local downPos = pos-Vector3.New(0,0.3,0)
                    tweener = tran:DOLocalMove(downPos,0.5):SetEase(Tweening.Ease.InCirc)
                    seq:Append(tweener)
                    tweener = tran:DOLocalMove(pos,0.5):SetEase(Tweening.Ease.OutCirc)
                    seq:Append(tweener)
                    seq:SetLoops(-1,Tweening.LoopType.Restart)
                    seq:PlayForward()
                end

            }

            self._iconCtrl:MakeObject(data)


            table.insert(self._arrowList,key)
        end
    end

end

