function LWonderManager:ShowHud(data)

    local hintdata = gModelWonderland:GetHintData(data.eventType)
    local value
    if data.eventType == 3 then
        value = data.effectVal
    else
        value = tonumber(data.effectVal) or 0
        value = math.floor(value *100)
    end
    local text = string.replace(ccLngText(hintdata.text),value)
    local hudData =
    {
        icon = hintdata.hint,
        text = text,
    }

    local isHurt = data.eventType ~= ModelWonderland.EVENT_REVIVAL and data.eventType ~= ModelWonderland.EVENT_SPRING

    if isHurt then
        FireEvent(EventNames.ON_WONDERLAND_GET_HURT)
    end

    self._roleObj:CreateHud(hudData)
end

function LWonderManager:RefreshRoleBuffShow()
    local eventId,round = gModelWonderland:GetRoleBuff()
    if not eventId or eventId == 0 then
        return
    end

    local eventCfg = gModelWonderland:GetEventConfig(eventId)
    if not eventCfg then
        return
    end
    local eventType = eventCfg.type
    if eventType ~= ModelWonderland.EVENT_POISON then
        return
    end
    local para  =eventCfg.parameter
    local strs = string.split(para,"=")
    local effName = strs[#strs]
    if not effName then
        return
    end
    if round>0 then
        local effData =
        {
            type = 1,
            effName = effName,
            scale = 1,
        }
        if self._roleObj then
            self._roleObj:AddEffect(effData)
        end
    else
        if self._roleObj then
            self._roleObj:DeleteEffect(effName)
        end
    end

end

function LWonderManager:RefreshSpecialEvent()
    local themeId = gModelWonderland:GetThemeId()
    local themeCfg = gModelWonderland:GetThemeConfig(themeId)
    local type = themeCfg.type
    if type == 5 then
        local eventdata = gModelWonderland:GetBeastEvent()
        if not eventdata then
            return
        end

        local eventObj = self._beastEventObj
        if eventObj then
            eventObj:Refresh(eventdata)
        else

            local eventId = eventdata.eventId
            local eventCfg = gModelWonderland:GetEventConfig(eventId)
            local resSize = eventCfg.resSize
            local resType = eventCfg.resType
            local res = eventCfg.res
            local layerIndex = eventdata.layerIndex
            local posY = layerIndex*0.8 -2
            local pos = Vector3.New(0,posY,0)
            local resOffset = self:GetTranPosition(eventCfg.resSite)/100
            pos = pos + resOffset
            local gridKey = -1
            local data =
            {
                position = pos,
                eventId = eventId,
                eventdata = eventdata,
                gridKey = gridKey,
                scale = resSize,
                resType = resType,
                res = res,
                sorting = LGamePlayType.WONDER_SORTING_ARROW+1,
                onLoaded = function()
                    self:CheckFollow()
                end,
            }
            eventObj = LWonderEventObj:New(self)
            self._beastEventObj = eventObj
            eventObj:Create(data)

            local isFirst = eventdata.layerIndex == 2 and not eventdata.isShowed

            if isFirst then
                eventdata.beastState = 2
                eventdata.isShowed = true
                if self:GetSettingAutoRunStatus() then return end
                GF.OpenWnd("UIEdenMonsterPop",{data= eventdata,eventType = ModelWonderland.EVENT_BEAST,wndType = 7})
            end
        end

    end
end

function LWonderManager:GetKelakenTran()
    if not self._beastEventObj then
        return
    end
    local spine = self._beastEventObj:GetSpineObject()
    if not spine or not spine:IsDpValid() then
        return
    end

    return spine:GetDisplayTrans()
end

function LWonderManager:SetKelakenFollow()
    self._follow = true
end

function LWonderManager:CheckFollow()
    if self._follow then
        FireEvent(EventNames.ON_FOLLOW_KELAKEN)
    end
end

function LWonderManager:GetTranPosition(str)
    local tempStr = string.split(str,";")
    local x = tonumber(tempStr[1] or 0)
    local y = tonumber(tempStr[2] or 0)

    return Vector3.New(x,y,0)

end

function LWonderManager:GetSettingAutoRunStatus()
    return gModelGameHelperAlleviation:CheckWonderlandIsAutoRun()
end

function LWonderManager:ShowWaitEffect()

    local eventType = self._waitEvent

    self._waitEvent = nil
    if eventType == ModelWonderland.EVENT_POD then

        local seq = self._seqCom:CreateSeq("delayPlayEff")
        seq:AppendInterval(0.5)
        seq:AppendCallback(function ()
            self:PlayBehit(40003)
        end)
        seq:AppendInterval(0.33)
        seq:OnComplete(function ()
            self._seqCom:DeleteSeq("delayPlayEff")
            self:RefreshRolePos()
        end)
        seq:PlayForward()


    elseif eventType == ModelWonderland.EVENT_BEAN_VINE then
        local seq = self._seqCom:CreateSeq("delayPlayEff")
        seq:AppendInterval(0.2)
        seq:OnComplete(function ()
            self._seqCom:DeleteSeq("delayPlayEff")
            self:RefreshRolePos()
        end)
        seq:PlayForward()
    else
        self:RefreshRolePos()
    end
end

function LWonderManager:ClearWhenExit()
    if self._roleObj then
        self._roleObj:Destroy()
        self._roleObj = nil
    end

    if self._seqCom then
        self._seqCom:Destroy()
        self._seqCom = nil
    end

    if self._beastEventObj then
        self._beastEventObj:Destroy()
        self._beastEventObj = nil
    end

    self:Clear()
end

function LWonderManager:Destroy()
    self:ClearWhenExit()
    LGpBaseMgr.Destroy(self)
end



return LWonderManager